parameters.jsCode:
const finding = $input.first().json;
const detail = finding.detail || finding;

const principal = detail.resource?.accessKeyDetails || {};
const network = detail.service?.action?.awsApiCallAction?.remoteIpDetails || {};

return [{
  json: {
    findingId: detail.id,
    findingType: detail.type,
    severity: detail.severity,
    region: detail.region || 'eu-central-1',
    accountId: detail.accountId,
    iamUserName: principal.userName || 'unknown',
    accessKeyId: principal.accessKeyId || 'unknown',
    principalId: principal.principalId || 'unknown',
    sourceIp: network.ipAddressV4 || 'unknown',
    sourceCountry: network.country?.countryName || 'unknown',
    apiCall: detail.service?.action?.awsApiCallAction?.api || 'unknown',
    timestamp: detail.updatedAt || new Date().toISOString(),
    incidentId: 'INC-AWS-' + Date.now().toString(36).toUpperCase()
  }
}];

